import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import api from "../api/client";
import { useAuth } from "../context/AuthContext";

export default function MoviesPage() {
  const [movies, setMovies] = useState([]);
  const [genres, setGenres] = useState([]);
  const [selectedGenre, setSelectedGenre] = useState(null);
  const { user } = useAuth();

  useEffect(() => {
    api.getGenres().then(setGenres);
  }, []);

  useEffect(() => {
    if (selectedGenre) {
      api.getMoviesByGenre(selectedGenre.id).then(data => setMovies(data || []));
    } else {
      api.getMovies().then(data => setMovies(data || []));
    }
  }, [selectedGenre]);

  const handleDelete = async (id) => {
    if (confirm("Delete this movie?")) {
      await api.deleteMovie(id);
      if (selectedGenre) {
        api.getMoviesByGenre(selectedGenre.id).then(data => setMovies(data || []));
      } else {
        api.getMovies().then(data => setMovies(data || []));
      }
    }
  };

  return (
    <div>
      <div className="genre-filter">
        <button
          className={`genre-btn ${!selectedGenre ? "active" : ""}`}
          onClick={() => setSelectedGenre(null)}
        >
          All Genres
        </button>
        {genres.map(g => (
          <button
            key={g.id}
            className={`genre-btn ${selectedGenre?.id === g.id ? "active" : ""}`}
            onClick={() => setSelectedGenre(g)}
          >
            {g.name}
          </button>
        ))}
      </div>

      <div className="movie-grid">
        {Array.isArray(movies) && movies.map(m => (
          <div key={m.id} className="movie-card">
            <img src={m.posterUrl} alt={m.title} className="movie-poster" />
            <div className="movie-info">
              <div className="movie-title">{m.title}</div>
              <div className="movie-year">{m.year}</div>
              <div className="movie-rating">⭐ {m.rating}/10</div>
              <div className="movie-actions">
                <Link to={`/movies/${m.id}`} className="btn btn-primary">View</Link>
                {user && (
                  <>
                    <Link to={`/movies/edit/${m.id}`} className="btn btn-warning">Edit</Link>
                    <button onClick={() => handleDelete(m.id)} className="btn btn-danger">Delete</button>
                  </>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
